sys_script.script:
/*jshint esnext: true */
(function executeRule(current, previous /*null when async*/ ) {

	// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
	// Script Continued Below

	var grRole;
	var UserPermissions = new UserInfoScripts();

	// STRY0076016
	if(!UserPermissions.userCanCreateMem(current.discover_office_hierarchy)){
		gs.addInfoMessage('Action not authorized');
		current.setAbortAction(true);
		return;
	}

	/*
	gs.info("KT OnInsert previous.is_global_tasking_authority: " + previous.is_global_tasking_authority);
	gs.info("KT OnInsert current.is_global_tasking_authority: " + current.is_global_tasking_authority);
	gs.info("KT OnInsert current.is_global_tasking_authority.changesTo('true'): " + current.is_global_tasking_authority.changesTo('true'));
	gs.info("KT OnInsert current.is_global_tasking_authority.changesTo('false'): " + current.is_global_tasking_authority.changesTo('false'));

	gs.info("KT OnInsert current.is_global_tasking_authority: " + current.is_global_tasking_authority);
	gs.info("KT OnInsert current.is_tasker_application_admin: " + current.is_tasker_application_admin);
	gs.info("KT OnInsert current.can_manage_process_permissions: " + current.can_manage_process_permissions);
	*/
	//-----------------------------------------------------------------------------------------------------
	// Role: Tasker User |  x_153465_discovert.tasker_user
	//-----------------------------------------------------------------------------------------------------
	if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_user'))
		gs.addInfoMessage('Role x_153465_discovert.tasker_user : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);


	// KT: Updated condition to changesTo() on 18-Jun-19
	//-----------------------------------------------------------------------------------------------------
	// Role: Global Tasking Authority | x_153465_discovert.tasker_global_Tasking_Authority_member_admin
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.is_global_tasking_authority) {
		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin')) {
			gs.addInfoMessage(' + Adding Role x_153465_discovert.tasker_global_Tasking_Authority_member_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncOtherGlobalField("is_global_tasking_authority", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		}

	} else syncCurrentGlobalField("is_global_tasking_authority", current); //Global Tasking Authority  //STRY0046028: 07.16.20


	// KT: Updated condition to changesTo() on 18-Jun-19
	//-----------------------------------------------------------------------------------------------------
	// Role: Global Hierarchy Administrator | x_153465_discovert.tasker_organizational_admin
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.user_is_organization_admin) {

		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_organizational_admin')) {
			gs.addInfoMessage('Role x_153465_discovert.tasker_organizational_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncOtherGlobalField("user_is_organization_admin", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		} 

	} else syncCurrentGlobalField("user_is_organization_admin", current); //Global Tasking Authority  //STRY0046028: 07.16.20


	// KT: Updated condition to changesTo() on 18-Jun-19
	//-----------------------------------------------------------------------------------------------------
	// Role: Tasker Application Admin | x_153465_discovert.tasker_application_admin
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.is_tasker_application_admin) {

		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_application_admin')){
			gs.addInfoMessage('Role x_153465_discovert.tasker_application_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncOtherGlobalField("is_tasker_application_admin", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		}

	} else syncCurrentGlobalField("is_tasker_application_admin", current); //Global Tasking Authority  //STRY0046028: 07.16.20


	// KT: Updated condition to changesTo() on 18-Jun-19
	//-----------------------------------------------------------------------------------------------------
	// Role: Process Template Permissions Administrator | x_153465_discovert.tasker_process_template_admin
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.can_manage_process_permissions) {

		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_admin')){
			gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncOtherGlobalField("can_manage_process_permissions", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		}

	} else syncCurrentGlobalField("can_manage_process_permissions", current); //Global Tasking Authority  //STRY0046028: 07.16.20


	// KT: Updated condition to changesTo() on 18-Jun-19
	//-----------------------------------------------------------------------------------------------------
	// Role: Global Process Template Administrator | x_153465_discovert.tasker_process_template_global
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.can_manage_global_processes) {

		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_global')){
			gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_global : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);
			syncOtherGlobalField("can_manage_global_processes", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		}

	} else syncCurrentGlobalField("can_manage_global_processes", current); //Global Tasking Authority  //STRY0046028: 07.16.20


	// RJ : Updated condition to changesTo() on 13-Sep-20
	//-----------------------------------------------------------------------------------------------------
	// Role: OU Template Designer -
		// NOTE: this is not a role any more, but it does require adding 
		// x_153465_discovert.tasker_process_template_user
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.has_ou_process_rights) {
		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_user')) {
			gs.addInfoMessage(' + User is an OU Template Designer.  Adding Role x_153465_discovert.tasker_process_template_user : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncOtherGlobalField("has_ou_process_rights", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		}

	} else syncCurrentGlobalField("has_ou_process_rights", current); //Global Tasking Authority  //STRY0046028: 07.16.20

	//-----------------------------------------------------------------------------------------------------
	// Role: Personal Process Template Administrator | role x_153465_discovert.tasker_process_template_user
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.has_personal_process_rights) {

		if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_user')){
			gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_user : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);
				syncOtherGlobalField("has_personal_process_rights", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20
		}

	} else syncCurrentGlobalField("has_personal_process_rights", current); //Global Tasking Authority  //STRY0046028: 07.16.20


	//STRY0046028: 07.16.20
	//syncCurrentGlobalField("is_global_tasking_authority", current); //Global Tasking Authority
	//syncCurrentGlobalField("user_is_organization_admin", current); //Global Hierarchy Administrator
	//syncCurrentGlobalField("is_tasker_application_admin", current); //Tasker Application Admin
	//syncCurrentGlobalField("can_manage_process_permissions", current); //Process Template Permissions Administrator
	//syncCurrentGlobalField("can_manage_global_processes", current); //Global Process Template Administrator
	//syncCurrentGlobalField("has_personal_process_rights", current); //Personal Process Template Administrator


	//-----------------------------------------------------------------------------------------------------
	// SYNC UP GLOBAL ROLES: GRABBED GLOBAL FLAG FROM OTHER OUS
	//-----------------------------------------------------------------------------------------------------
	function syncCurrentGlobalField(field, current) {
		var grCurrentUserOU = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grCurrentUserOU.addQuery('office_member', current.office_member);
		grCurrentUserOU.addQuery('discover_office_hierarchy', '!=', current.discover_office_hierarchy);
		grCurrentUserOU.addQuery(field, true); //Field Role
		grCurrentUserOU.query();
		//gs.info("KT grCurrentUserOU query: " + grCurrentUserOU.getEncodedQuery().toString());

		while (grCurrentUserOU.next()) {
			current.setValue(field, true); //Field Role
			//gs.info("KT " + current.office_member + " is " + field + " ?   " + current.is_global_tasking_authority);
		}
	}


	//-----------------------------------------------------------------------------------------------------
	// SYNC UP GLOBAL ROLES: PUSH GLOBAL FLAG TO OTHER OUS
	//-----------------------------------------------------------------------------------------------------
	function syncOtherGlobalField(field, current, flag) {
		var grCurrentUserOU = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grCurrentUserOU.addQuery('office_member', current.office_member);
		grCurrentUserOU.addQuery('discover_office_hierarchy', '!=', current.discover_office_hierarchy);
		grCurrentUserOU.addQuery(field, !flag); //Field Role
		grCurrentUserOU.query();
		//gs.info("KT grCurrentUserOU query: " + grCurrentUserOU.getEncodedQuery().toString());

		while (grCurrentUserOU.next()) {
			grCurrentUserOU.setValue(field, flag); //Field Role
			grCurrentUserOU.update();
			//gs.info("KT " + current.office_member + " is " + field + " ?   " + flag);
		}
	}


})(current, previous);
